function generate(symbol) {
  const code = symbol.charCodeAt(0);
  if (code >= 97 && code <= 122) {
    return (code - 97 + 10).toString(16);
  }
  if (code >= 65 && code <= 90) {
    return (code - 65 + 10).toString(16);
  }
  if (code >= 48 && code <= 57) {
    return (code - 48 + 20).toString(16);
  }
  return null;
}

