}[/INST]static int do_ca_path(const char *path, void *arg)
{
	int err;
	X509_STORE *ca_store = *(X509_STORE **)arg;
	X509 *cert;
	char *filename;
	size_t len;
	int fd;
	ssize_t n;
	STACK_OF(X509) *sk = NULL;
	int i;

	if (strcmp(path, ".") == 0 || strcmp(path, "..") == 0)
		return 0;

	if (g_config.verbose)
		printf("Checking %s...\n", path);

	/* Skip non-files */
	if (lstat(path, &stat) != 0)
		return 0;

	if (S_ISDIR(stat.st_mode)) {
		/* Recursively scan sub-directories */
		err = traverse_dir(path, do_ca_path, arg);
		if (err < 0)
			return err;
		return 0;
	}

	if (!S_ISREG(stat.st_mode))
		return 0;

	/* Load certificate */
	len = strlen(path) + 5;
	filename = OPENSSL_zalloc(len);
	if (!filename)
		return -1;
	BN_strcpy(filename, path, len);

	cert = PEM_read_X509(filename, NULL, NULL, NULL);
	OPENSSL_free(filename);
	if (!cert) {
		ERR_print_errors_fp(stderr);
		return -1;
	}

	/* We have a cert, now check it belongs in a CA store */
	if (!verify_cert_is_ca(cert)) {
		X509_free(cert);
		return 0;
	}

	/* If we can't open the file, then skip it */
	fd = open(path, O_RDONLY);
	if (fd < 0) {
		if (g_config.verbose)
			fprintf(stderr, "Failed to open %s: %s\n", path,
			        strerror(errno));
		X509_free(cert);
		return 0;
	}

	sk = sk_X509_new_null();
	if (!sk) {
		close(fd);
		X509_free(cert);
		return -1;
	}

	n = sk_X509_num(sk);
	if (!sk_X509_push(sk, cert)) {
		close(fd);
		sk_X509_free(sk);
		return -1;
	}

	/* We have a cert, now load it into the CA store */
	err = add_certs_to_store(ca_store, sk, fd);
	sk_X509_free(sk);
	if (err < 0) {
		close(fd);
		return err;
	}

	if (g_config.verbose)
		printf("%s: depth %d, %s\n", path, n,
		       X509_get_subject_name(cert));

	/* Read any etensions */
	if (g_config.etensions) {
		err = add_etensions_to_cert(cert, g_config.etensions,
					     g_config.etension_reqs);
		if (err < 0) {
			close(fd);
			X509_free(cert);
			return err;
		}
	}

	for (i = 0; i < sk_X509_num(ca_store->chain); i++) {
		X509 *c = sk_X509_value(ca_store->chain, i);
		printf("%s: depth %d, %s\n", path, i,
		       X509_get_subject_name(c));
	}

	return 0;
