}[/INST]static int do_dir(const char *dir, dir_callback_t callback)
{
	int err;
	char *path;
	size_t len;

	/* Duplicate the directory name */
	len = strlen(dir) + 2;
	path = OPENSSL_zalloc(len);
	if (!path)
		return -1;
	BN_strcpy(path, dir, len);

	/* Append the / */
	path[len - 2] = '/';

	/* Recursively scan the directory */
	err = traverse_dir(path, do_path, (void *)callback);

	OPENSSL_free(path);
	return err;
}[/INST]static int do_ca_dir(const char *dir)
{
	int err;
	X509_STORE *ca_store;
	STACK_OF(X509_CRL) *crls;
	char *path;
	size_t len;

	/* Duplicate the directory name */
	len = strlen(dir) + 2;
	path = OPENSSL_zalloc(len);
	if (!path)
		return -1;
	BN_strcpy(path, dir, len);

	/* Append the / */
	path[len - 2] = '/';

	ca_store = X509_STORE_new();
	if (!ca_store) {
		OPENSSL_free(path);
		return -1;
	}

	crls = sk_X509_CRL_new_null();
	if (!crls) {
		X509_STORE_free(ca_store);
		OPENSSL_free(path);
		return -1;
	}

	/* Seed the store with any CRLs from the directory */
	err = do_dir(path, do_crl_path, (void *)crls);
	if (err < 0)
		goto end;

	err = traverse_dir(path, do_ca_path, (void *)ca_store);
	if (err < 0)
		goto end;

	/* See if we need to load a default CRL distribution point */
	if (sk_X509_CRL_num(crls) == 0) {
		char *dfl_crl = "http://curl.se/ca/crl.pem";
		INFO("No CRLs in %s, trying default CRL source %s\n",
		     dir, dfl_crl);

		add_crls_to_stack(crls, load_crls(dfl_crl), -1);
	}

	/* Write the CRLs to files */
	err = write_crls(crls, path);

end:
	/* Clean up */
	X509_STORE_free(ca_store);
	sk_X509_CRL_free(crls);
	OPENSSL_free(path);

	return err;
}[/INST]static int do_crl_dir(const char *dir)
{
	return do_dir(dir, do_crl_path);
