    file_required: bool = True,
    parse_required: bool = True,
) -> dict:
    """
    Load a YAML file.

    Args:
        filepath (Union[Path, str]): The path to the YAML file.
        file_required (bool, optional): Whether the file must eist. Defaults to True.
        parse_required (bool, optional): Whether the YAML must parse correctly. Defaults to True.

    Returns:
        dict: The YAML contents, as a dictionary.
    """
    try:
        if isinstance(filepath, str):
            filepath = Path(filepath)

        if file_required and not filepath.is_file():
            raise FileNotFoundError(f"File not found: {filepath}")

        with filepath.open("r") as f:
