def check_featureset(self, features):
        """Check a featureset against various criteria.

        :param features: A dictionary mapping feature names to version tags.
        :raises jhbuild.errors.MissingTagError: When a feature's tag isn't
            found in the tag registry.
        :raises jhbuild.errors.InvalidVersionTagError: When a feature's version
            tag isn't valid.
        :raises jhbuild.errors.InvalidBugzillaTagError: When a feature's
            bugzilla tag isn't valid.
        """
        for name, tag in features.items():
            if tag in self.tagregistry:
                continue
            if self.config.version_tag_pattern.match(tag):
                continue
            if self.config.bugzilla_tag_pattern.match(tag):
                continue
            raise errors.MissingTagError(name, tag)

        for name, tag in features.items():
            if self.config.version_tag_pattern.match(tag):
                continue
            try:
                self.get_tag_revision(tag)
            except errors.SubversionError:
                raise errors.InvalidVersionTagError(name, tag)

