			const string &out_tile_file)
{
  ifstream tile_in1(tile_file1.c_str());
  ifstream tile_in2(tile_file2.c_str());
  ofstream tile_out(out_tile_file.c_str());

  string line;
  getline(tile_in1, line);
  tile_out << line << endl;
  int num_tiles = atoi(line.c_str());

  vector<string> tile1;
  vector<string> tile2;

  for (int i = 0; i < num_tiles; i++) {
    getline(tile_in1, line);
    tile1.push_back(line);
    getline(tile_in2, line);
    tile2.push_back(line);
  }

  for (int i = 0; i < num_tiles; i++) {
    int tile1_id = atoi(tile1[i].c_str());
    int tile2_id = atoi(tile2[i].c_str());
    int new_id = 2 * tile1_id + tile2_id;
    tile_out << new_id << " " << tile1[i].substr(5) << " "
	    << tile2[i].substr(5) << endl;
  }
}

