def parse_args():
    parser = argparse.ArgumentParser(
        description='Run a hardware simulation tool (hwsim).',
        epilog='Report bugs to <https://github.com/YosysHQ/yosys/issues>'
    )

    parser.add_argument(
        '-V', '--version', action='version',
        version='%(prog)s ' + __version__
    )

    parser.add_argument(
        '-l', '--log', metavar='FILE', default=None,
        help='write log to FILE'
    )

    parser.add_argument(
        '-s', '--script', metavar='FILE',
        help='run script FILE'
    )

    parser.add_argument(
        '-v', '--verbose', action='count', default=0,
        help='increase output verbosity'
    )

    parser.add_argument(
        '-t', '--target', metavar='TARGET',
        help='set target device'
    )

    parser.add_argument(
        '-p', '--param', action='append', metavar='PARAM=VALUE',
        help='set parameter'
    )

    parser.add_argument(
        '-F', '--frontend', metavar='FRONTEND',
        help='set frontend'
    )

    parser.add_argument(
        '-P', '--synth', metavar='SYNTH',
        help='set synthesis tool'
    )

    parser.add_argument(
        '-i', '--impl', metavar='IMPL',
        help='set place-and-route tool'
    )

    parser.add_argument(
        '-d', '--dir', metavar='DIR', default='.',
        help='set working directory'
    )

    parser.add_argument(
        'toplevel', nargs='?',
        help='set top-level module'
    )

    args = parser.parse_args()

    if args.log:
        logging.basicConfig(filename=args.log, level=logging.DEBUG)
    else:
        logging.basicConfig(level=logging.WARNING)

    if args.verbose == 0:
        logging.getLogger('hwsim').setLevel(logging.INFO)
    elif args.verbose == 1:
        logging.getLogger('hwsim').setLevel(logging.DEBUG)
    elif args.verbose > 1:
        logging.getLogger('hwsim').setLevel(1)

    if args.param is None:
        args.param = []
    args.param_dict = {p.split('=', 1)[0]: p.split('=', 1)[1]
                       for p in args.param}

    return args


def main():
    args = parse_args()

    try:
        run(args)
    except hwsim.HwSimError as e:
        logging.error(str(e))
        return 1
    return 0


def run(args):
    if args.log:
        log_file = Path(args.log).resolve()
        log_size = log_file.stat().st_size
        if log_size > 1000000:
            logging.warning(f'Log file {log_file} is {log_size} bytes, consider using a different log file.')

    if args.script:
        run_script(args)
    else:
        hwsim.main_main(args)


def run_script(args):
    script_file = Path(args.script).resolve()
    if not script_file.is_file():
        raise hwsim.HwSimError(f'Script file {script_file} does not eist')

    with open(script_file, 'r') as f:
        script = f.read()

    yaml_data = yaml.load(script, Loader=yaml.FullLoader)
    if yaml_data is None:
        yaml_data = {}

    if isinstance(yaml_data, list):
        for data in yaml_data:
            run_command(args, data)
    elif isinstance(yaml_data, dict):
        run_command(args, yaml_data)
    else:
        raise hwsim.HwSimError('Top-level value in script must be a dict or a list of dicts')


def run_command(args, data):
    command = data.get('command')
    if command == 'run':
        run_args = data.get('args', {})
        run_args['script'] = None
        run_args['toplevel'] = data.get('top', args.toplevel)
        run_args['target'] = data.get('target', args.target)
        run_args['dir'] = data.get('dir', args.dir)
        run_args['param'] = [f"{k}={v}" for k, v in data.get('param', {}).items()]
        run_args['verbose'] = args.verbose + 1
        run_args = argparse.Namespace(**run_args)
        run(run_args)
    elif command == 'assert':
        top = data.get('top', args.toplevel)
        if top is None:
            raise hwsim.HwSimError('"assert" command without "top" field')
        celltype = data.get('celltype')
        ports = data.get('ports', {})
        netlist_file = data.get('netlist')
        if netlist_file:
            netlist_file = Path(netlist_file).resolve()
        intree = data.get('intree')
        if intree:
            intree = Path(intree).resolve()
        hwtest.main_main(args, top, celltype, ports, netlist_file, intree)
    else:
        raise hwsim.HwSimError(f'Unknown command: {command}')

