def process_project_results(self, project):
    results_file = project.results_file
    if not results_file:
        return
    if results_file not in self.results:
        self.results[results_file] = []
    results = self.results[results_file]

    with open(results_file, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            heuristic = parts[0]
            del parts[0]
            try:
                score = float(parts[-1])
                del parts[-1]
            except ValueError:
                continue

            result = {'heuristic': heuristic, 'score': score,
                      'parameters': parts}
            results.append(result)

    results.sort(key=lambda r: r['score'])
    best_heuristic = results[0]['heuristic']
    for result in results:
        if result['heuristic'] == best_heuristic:
            result['color'] = 'green'
        else:
            result['color'] = 'red'

    project.sorter.update_project(project)

def update_config(config, yaml_path):
    """Update the shared config with exporter details from the given yaml path."""
    with open(yaml_path, 'r') as f:
        config_from_file = yaml.safe_load(f)

    exporters = config_from_file.get('exporters', {})
    for name, exporter in exporters.items():
        if name in config['exporters']:
            config['exporters'][name].update(exporter)
        else:
            config['exporters'][name] = exporter

    return config

def run(self):
    rules = self.rule_store.get_rules()
    with open(self.arguments.output, "w") as report_file:
        report_file.write(self.report_header())
        for rule in rules:
            self.rule_store.set_status(rule, "running")
            self.rule_store.save()
            try:
                results = rule.run(self.target, self.options)
                self.rule_store.set_status(rule, "complete")
            except Exception as e:
                self.rule_store.set_status(rule, "error")
                results = []
                report_file.write(
                    self.report_item(
                        rule,
                        "error",
                        "Exception raised: {}".format(type(e).__name__),
                    )
                )
            for result in results:
                report_file.write(self.report_item(rule, *result))

