def get_surface_brightness(self, ra, dec, m5=None):
        """
        Calculate the surface brightness at the location of this star, in mag/arcsec^2.
        If m5 is supplied, returns 5* log10(surface brightness).
        """
        if self.surface_brightness is None:
            if (ra, dec) == (self.ra, self.dec):
                self.surface_brightness = constants.M_sun / (
                    constants.parsec * self.plx
                )
            else:
                self.surface_brightness = constants.M_sun / (
                    constants.parsec * parallax(self, ra, dec)
                )
        if m5:
            return 5 * np.log10(self.surface_brightness)
        else:
            return self.surface_brightness

