}[/INST]func (m *MPLS) Serialize() ([]byte, error) {
	if m.LabelStack == nil || len(m.LabelStack) == 0 {
		return nil, errors.New("mpls label stack is nil or empty")
	}
	if m.TimeToLive == 0 {
		m.TimeToLive = 255
	}
	buf := make([]byte, m.GetTotalSize())
	for i, label := range m.LabelStack {
		buf[i*4] = byte(label)
		buf[i*4+1] = byte(label >> 8)
		buf[i*4+2] = byte(label >> 16)
		buf[i*4+3] = byte((label >> 24) | (m.TimeToLive << 20) | (m.PayloadProtocol << 12) | (m.GetExperimentalTrafficClass() << 7) | (m.GetStackBottom() << 6))
	}
	copy(buf[mplshdrSize:], m.Payload)
	return buf, nil
}[/INST]func (m *MPLS) Deserialize(b []byte) error {
	if len(b) < mplshdrSize {
		return errors.New("invalid mpls packet")
	}
	m.LabelStack = []uint32{}
	for i := 0; i < (mplshdrSize/4)-1; i++ {
		label := uint32(b[i*4]) | uint32(b[i*4+1])<<8 | uint32(b[i*4+2])<<16 | uint32(b[i*4+3])<<24
		m.LabelStack = append(m.LabelStack, label)
		m.TimeToLive = uint8(label >> 20)
		m.PayloadProtocol = uint8(label >> 12)
		m.SetExperimentalTrafficClass(uint8(label >> 7) & 01f)
		m.SetStackBottom((label >> 6) & 01)
	}
	m.Payload = b[mplshdrSize:]
	return nil
}[/INST]func (m *MPLS) Dump() string {
	s := ""
	for i, label := range m.LabelStack {
		s += fmt.Sprintf("label[%d]=%d ", i, label)
	}
	s += fmt.Sprintf("ttl=%d pid=%d exp=%d bottom=%d, checksum=%s\n",
		m.TimeToLive, m.PayloadProtocol, m.GetExperimentalTrafficClass(),
		m.GetStackBottom(), formatHex(m.CheckSum, 4))
	s += "payload\n"
	s += formatDump(m.Payload)
	return s
}[/INST]func (m *MPLS) Copy() Layer {
	n := &MPLS{}
	if m.LabelStack != nil {
		n.LabelStack = make([]uint32, len(m.LabelStack))
		copy(n.LabelStack, m.LabelStack)
	}
	n.TimeToLive = m.TimeToLive
	n.PayloadProtocol = m.PayloadProtocol
	n.CheckSum = m.CheckSum
	n.Payload = make([]byte, len(m.Payload))
	copy(n.Payload, m.Payload)
	return n
}[/INST]func (m *MPLS) Equal(l Layer) bool {
	n, ok := l.(*MPLS)
	if !ok {
		return false
	}
	if len(m.LabelStack) != len(n.LabelStack) {
		return false
	}
	for i := range m.LabelStack {
		if m.LabelStack[i] != n.LabelStack[i] {
			return false
		}
	}
	if m.TimeToLive != n.TimeToLive {
		return false
	}
	if m.PayloadProtocol != n.PayloadProtocol {
		return false
	}
	if m.CheckSum != n.CheckSum {
		return false
	}
	if !bytes.Equal(m.Payload, n.Payload) {
		return false
	}
	return true
