func (b *bot) handleStreamStatus(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	if vars["challenge"] != "" {
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(vars["challenge"]))
		return
	}

	b.m.Lock()
	defer b.m.Unlock()

	if !b.config.StreamNotify {
		return
	}

	if r.Method != http.MethodPost {
		w.WriteHeader(http.StatusNotFound)
		return
	}

	var payload streamPayload
	if err := json.NewDecoder(r.Body).Decode(&payload); err != nil {
		b.log.Println("ERROR:", err)
		w.WriteHeader(http.StatusInternalServerError)
		return
	}
	defer r.Body.Close()

	switch payload.Stream.Status {
	case "online":
		b.log.Println("INFO: Stream is online!")
		for _, c := range b.config.NotifyChannels {
			_, err := b.discord.Send(c, "Online!")
			if err != nil {
				b.log.Println("ERROR:", err)
			}
		}
	case "offline":
		b.log.Println("INFO: Stream is offline!")
		for _, c := range b.config.NotifyChannels {
			_, err := b.discord.Send(c, "Offline!")
			if err != nil {
				b.log.Println("ERROR:", err)
			}
		}
	}
}

