	id := chi.URLParam(r, "id")
	c, err := cli.backend.LoadContainer(r.Context(), id)
	if err != nil {
		http.Error(w, err.Error(), http.StatusNotFound)
		return
	}
	if c.IsPaused() {
		http.Error(w, "Cannot attach to a paused container", http.StatusConflict)
		return
	}
	streamer, err := cli.backend.ContainerAttach(r.Context(), id, r.Form.Get("stream") == "true")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer streamer.Close()
	// if we are not streaming, we do not need to copy anything
	if !streamer.Stream() {
		return
	}

	ws, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer ws.Close()
	// copy container output to response
	_, err = io.Copy(ws, streamer)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
