func getAuthenticatedBasket(w http.ResponseWriter, r *http.Request, ps httprouter.Params) (string, Basket) {
	name := ps.ByName("basket")
	if name == "" {
		http.Error(w, "No basket name provided", http.StatusBadRequest)
		return "", Basket{}
	}
	basket, err := getBasket(name)
	if err != nil {
		http.Error(w, "Basket not found", http.StatusNotFound)
		return "", Basket{}
	}
	if !basket.IsAuthorized(r) {
		http.Error(w, "Not authorized", http.StatusForbidden)
		return "", Basket{}
	}
	return name, basket
}

