func (my *basketService) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	name := vars["name"]

	if name == "" {
		http.Error(w, "name is required", http.StatusBadRequest)
		return
	}

	if err := my.validateName(name); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	switch r.Method {
	case "GET":
		my.get(w, r, name)
	case "POST":
		my.post(w, r, name)
	case "PUT":
		my.put(w, r, name)
	case "DELETE":
		my.delete(w, r, name)
	default:
		http.Error(w, "invalid method", http.StatusMethodNotAllowed)
	}
}

