public void displayErrorPage(HttpServletRequest request, HttpServletResponse response, Exception e)
{
	Writer out = null;
	boolean isErr = false;
	try
	{
		// Set response status
		if (e instanceof ResourceNotFoundException)
		{
			response.setStatus(HttpServletResponse.SC_NOT_FOUND);
		}
		else if (e instanceof AccessDeniedException)
		{
			response.setStatus(HttpServletResponse.SC_FORBIDDEN);
		}
		else
		{
			response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
		}

		// Write response
		out = response.getWriter();
		isErr = true;
		out.write("<html>");
		out.write("<head>");
		out.write("<title>Error</title>");
		out.write("</head>");
		out.write("<body>");
		out.write("<h2>Error</h2>");
		out.write("<pre>");
		if (e instanceof ResourceNotFoundException)
		{
			out.write("Resource not found: ");
			out.write(((ResourceNotFoundException) e).getResource());
		}
		else if (e instanceof AccessDeniedException)
		{
			out.write("Access denied");
		}
		else
		{
			out.write("Internal server error");
		}
		out.write("</pre>");
		out.write("<h3>Stack trace</h3>");
		out.write("<pre>");
		e.printStackTrace(out);
		out.write("</pre>");
		out.write("</body>");
		out.write("</html>");
	}
	catch (IOException ioe)
	{
		if (isErr)
		{
			try
			{
				response.reset();
			}
			catch (IllegalStateException ise)
			{
				// Ignore
			}
		}
		getLogger().log(Level.SEVERE, null, ioe);
	}
	finally
	{
		if (out != null)
		{
			try
			{
				out.close();
			}
			catch (IOException ioe)
			{
				getLogger().log(Level.SEVERE, null, ioe);
			}
		}
	}
