    const name = document.createElement('span');
    name.className = 'filelist-name';
    name.textContent = file.name;
    row.appendChild(name);

    const size = document.createElement('span');
    size.className = 'filelist-size';
    if (file.size >= 1024 * 1024) {
      size.textContent = `${Math.round(file.size / (1024 * 1024))} MB`;
    } else if (file.size >= 1024) {
      size.textContent = `${Math.round(file.size / 1024)} kB`;
    } else {
      size.textContent = `${file.size} B`;
    }
    row.appendChild(size);

    const type = file.name.split('.').pop().toLowerCase();
    let bgImage = 'static/img/unknown.png';
    if (['png', 'jpg', 'jpeg', 'gif', 'bmp', 'svg'].includes(type)) {
      bgImage = `url(${URL.createObjectURL(file)})`;
    } else if (['mp4', 'avi', 'mkv', 'mov', 'flv', 'wmv'].includes(type)) {
      bgImage = `url(static/img/${type}.png)`;
    }
    row.style.backgroundImage = bgImage;

    fileList.appendChild(row);
  }
}

