function refreshDisplay() {
	var self = this;

	// Clear out the display
	self.$el.html('');

	// Get the list of items to display, based on the current search string
	var displayItems = self.getDisplayItems();

	// If we have a search input, show it
	if (self.searchable) {
		self.$searchEl.html(self.getSearchTemplate());
		self.$el.append(self.$searchEl);
	}

	// If we have groups, render those
	if (self.hasGroups()) {
		self.$el.append(self.getGroupTemplate({
			group: {
				name: self.opt('groupLabel')
			},
			items: displayItems
		}));
	} else {
		// Otherwise, render the items directly
		$.each(displayItems, function(i, item) {
			self.addItemDisplay(item);
		});
	}

	// Trigger a resize on the container in case the content has changed in a way
	// that would require the container to grow (e.g. scrollbar appearing)
	self.$container.trigger('resize');

	// Update the size/position of the search element
	self.updateSearchPosition();

	// Show / hide the "no items found" message
	if (self.isEmpty()) {
		self.$el.append(self.getNoResultsTemplate());
	}
}

