function onSearch(query) {
  clearErrors();
  showSpinner(true);
  updateUIResultsCount(0, true);

  controller
    .search(query)
    .then(results => {
      showSpinner(false);
      if (results.length === 0) {
        updateUIResultsCount(0, true);
        showNoResults(true);
      } else {
        showNoResults(false);
        updateUIResultsCount(results.length, false);
        resultsList.updateResults(results);
      }
    })
    .catch(err => {
      console.error(err);
      showSpinner(false);
      showNoResults(false);
      updateUIResultsCount(0, true);
      appendError(err);
    });
}

