function edit_item(item_id, element) {
  var url = '/edit/' + item_id;
  var csrf_token = document.getElementById('csrf_token').value;

  var options = {
    method: 'get',
    url: url,
    headers: { 'X-CSRF-Token': csrf_token }
  };

  ajax(options, function (data) {
    var form = document.createElement('form');
    form.innerHTML = data;
    form['new_content'].focus();

    form.onsubmit = function (e) {
      e.preventDefault();
      var new_content = form['new_content'].value;

      var url = '/update/' + item_id;
      var csrf_token = document.getElementById('csrf_token').value;

      var options = {
        method: 'post',
        url: url,
        headers: { 'X-CSRF-Token': csrf_token },
        body: 'new_content=' + encodeURIComponent(new_content)
      };

      ajax(options, function (data) {
        element.innerHTML = new_content;
        element.classList.remove('editable');
      });
    };

    element.innerHTML = '';
    element.appendChild(form);
    element.classList.add('editable');
  });
}

