function updateData(entry, column, value) {
    if (column === "grade") {
        if (value === "") {
            entry[column] = null;
        } else if (value.startsWith("http")) {
            entry[column] = value;
            entry.grade_type = "url";
        } else {
            entry[column] = parseFloat(value);
            entry.grade_type = "number";
        }
    } else {
        entry[column] = value;
    }
    return entry;
}

