function init_wysiwyg_editor(settings) {
	var editor = {
		settings: settings,
		tinymce: null,
		initialized: false,
		$node: null,
		$editor: null,
		$toolbar: null,
	};

	editor.$node = $('#'+settings.id);

	editor.$node.on('remove', function() {
		if (editor.tinymce) {
			editor.tinymce.destroy();
		}
	});

	var setup_tinymce = function() {
		var settings = editor.settings;
		var default_settings = {
			selector: '#' + settings.id,
			body_class: settings.body_class,
			plugins: 'lists link image preview anchor code',
			toolbar: 'formatselect | bold italic backcolor | \
				numlist bullist outdent indent | removeformat | help',
