		};

		$.extend(default_settings, settings.tinymce);

		tinymce.init(default_settings).then(function (mce) {
			editor.tinymce = mce;
			editor.$editor = $(mce.getContentAreaContainer());
			editor.$toolbar = editor.$node.find('.mce-toolbar');

			editor.$editor
				.on('blur', function() { editor.$node.trigger('blur'); })
				.on('focus', function() { editor.$node.trigger('focus'); });

			editor.$node
