				.addClass('wysiwyg')
				.wysiwyg_buttons()
				.wysiwyg_media();

			editor.initialized = true;

			if (settings.autofocus)
				editor.$editor.focus();

			if (typeof settings.oninit == 'function')
				settings.oninit(editor);
		});
	};

	if (typeof settings.tinymce == 'undefined' || typeof tinymce == 'undefined')
