function displayNewMessage(message) {
  const container = document.getElementById('message-container');
  const chatbot = document.getElementById('chatbot');
  const messages = container.getElementsByTagName('p');
  const lastMessage = messages[messages.length - 1];
  const botIsSpeaking = lastMessage && lastMessage.classList.contains('bot');
  const messageIsFromBot = message.speaker === 'bot';

  if (botIsSpeaking && messageIsFromBot) {
    updateLastMessage(message);
  } else {
    const paragraph = document.createElement('p');
    const messageClass = messageIsFromBot ? 'bot' : 'user';
    paragraph.classList.add(messageClass);
    paragraph.innerText = message.body;
    container.appendChild(paragraph);
    if (shouldAnnounce(message)) {
      announce(message);
    }
  }

  if (message.scrollIntoView) {
    setTimeout(() => {
      container.scrollTop = container.scrollHeight;
      if (chatbot) {
        chatbot.focus();
      }
    }, 50);
  }
