$(function() {
  // Set up the contact list.
  var contacts = {
    "joe schmoe": {phone: "555-1234", addr: "123 N. Main J. S."},
    "jane doe": {phone: "555-5678", addr: "456 E. 1st A. D."},
    "mr. t": {phone: "555-9012", addr: "789 W. 2nd St. T."}
  };
  var $contactList = $("#contactList");
  var contactTemplate = $("#contactTemplate").html();
  Mustache.parse(contactTemplate);
  function renderContacts(contacts) {
    $contactList.empty();
    $.each(contacts, function(name, contact) {
      var html = Mustache.render(contactTemplate, {name: name, phone: contact.phone, addr: contact.addr});
      $contactList.append(html);
    });
  }
  renderContacts(contacts);

  // Update the contact list when the name input changes.
  var $nameInput = $("#name");
  $nameInput.change(function() {
    var name = $nameInput.val().toLowerCase();
    if (name) {
      var contact = contacts[name];
      if (contact) {
        renderContacts(contact);
      } else {
        $contactList.empty();
        var html = Mustache.render(contactTemplate, {name: name, phone: "", addr: ""});
        $contactList.append(html);
      }
    } else {
      renderContacts(contacts);
    }
  });

  // Set up the sorting.
  $("#sortPhone").click(function() {
    var sortedContacts = [];
    $.each(contacts, function(name, contact) {
      sortedContacts.push({name: name, phone: contact.phone});
    });
    sortedContacts.sort(function(a, b) {
      return a.phone < b.phone ? -1 : a.phone > b.phone ? 1 : 0;
    });
    var phoneMap = {};
    $.each(sortedContacts, function(i, contact) {
      phoneMap[contact.phone] = i;
    });
    var sortedContacts2 = [];
    $.each(contacts, function(name, contact) {
      sortedContacts2.push({name: name, addr: contact.addr, phoneInd: phoneMap[contact.phone]});
    });
    sortedContacts2.sort(function(a, b) {
      return a.phoneInd < b.phoneInd ? -1 : a.phoneInd > b.phoneInd ? 1 : 0;
    });
    renderContacts(sortedContacts2);
  });

  $("#sortAddr").click(function() {
    var sortedContacts = [];
    $.each(contacts, function(name, contact) {
      sortedContacts.push({name: name, addr: contact.addr});
    });
    sortedContacts.sort(function(a, b) {
      return a.addr < b.addr ? -1 : a.addr > b.addr ? 1 : 0;
    });
    renderContacts(sortedContacts);
  });

  $("#sortName").click(function() {
    renderContacts(contacts);
  });
});

