function setupInteractions() {
  // Handle click on table rows to open the detail pane
  document.querySelectorAll("table#mainTable tbody tr").forEach((row) => {
    row.addEventListener("click", (e) => {
      if (e.target.tagName === "TD") {
        const rowIndex = e.target.parentNode.rowIndex - 1;
        if (rowIndex === -1) return; // header clicked

        const detailPane = document.getElementById("detailPane");
        const detailContent = document.getElementById("detailContent");

        if (detailPane.classList.contains("open")) {
          // close it
          detailPane.classList.remove("open");
          return;
        }

        // build the detail content
        const detail = createDetailDiv(dataStore[rowIndex]);
        detailContent.innerHTML = "";
        detailContent.appendChild(detail);

        // open it
        detailPane.classList.add("open");
      }
    });
  });

  // Handle clicks on the detail pane bg to close it
  document
    .getElementById("detailPane")
    .addEventListener("click", (e) => {
      if (e.target.id === "detailPane") {
        e.target.classList.remove("open");
      }
    });

  // Handle checkbox updates
  document.querySelectorAll("#mainTable input[type=checkbox]").forEach((cb) => {
    cb.addEventListener("change", (e) => {
      const row = e.target.parentNode.parentNode;
      if (e.target.checked) {
        row.classList.add("selected");
      } else {
        row.classList.remove("selected");
      }
    });
  });

  // Handle "select all" checkbox
  const mainCheckbox = document.getElementById("selectAll");
  mainCheckbox.addEventListener("change", (e) => {
    const isChecked = e.target.checked;
    document
      .querySelectorAll("#mainTable input[type=checkbox]")
      .forEach((cb) => {
        if (cb.id === "selectAll") return;
        cb.checked = isChecked;
        if (isChecked) {
          cb.parentNode.parentNode.classList.add("selected");
        } else {
          cb.parentNode.parentNode.classList.remove("selected");
        }
      });
  });

  // handle sort
  document.querySelectorAll("#mainTable th").forEach((th) => {
    th.addEventListener("click", (e) => {
      const column = e.target.dataset.column;
      if (!column) return;

      // if we're already sorting by this column, reverse the sort order
      // otherwise, sort ascending
      let direction = 1;
      if (sortColumn === column) {
        direction = -1;
      }
      sortTable(column, direction);
      updateSortIcon(e.target, direction);
    });
  });

  // set up the filters
  document.querySelectorAll("#filters input").forEach((input) => {
    input.addEventListener("keyup", (e) => {
      filterTable(e.target);
    });
  });
} // setupInteractions() [END]

