function generate_html_list(results) {
  var html = "<ul>";
  for (var i = 0; i < results.length; i++) {
    var r = results[i];
    html += "<li>";
    if (r.link) {
      html += "<a href='" + r.link + "'>" + r.text + "</a>";
    } else {
      html += r.text;
    }
    html += "</li>";
  }
  html += "</ul>";
  return html;
}

