        minLength: 2
    });
    $("#add").click(function () {
        var inputVal = $("#tags").val();
        if (inputVal.length >= 2) {
            var li = $("<li></li>").text(inputVal);
            $("#sortable").append(li);
            var option = $("<option></option>").attr("value", inputVal).text(inputVal);
            $("#cat").append(option);
            $("#tags").val("");
        }
    });
    $("#sortable").disableSelection();
    $("#tags").keypress(function (e) {
        if (e.which == 13) {
            $("#add").click();
            return false;
        }
    });
});

