from typing import *
from collections import *

from flask import Flask, request, jsonify, abort
from datasketch import MinHash, MinHashLSH

app = Flask(__name__)

# variable storage
variables = {}

@app.route('/variables', methods=['GET', 'POST'])
def handle_variables():
    if request.method == 'POST':
        data = request.get_json(force=True)
        if not isinstance(data, dict):
            abort(400)

        # store data
        for k, v in data.items():
            variables[k] = v

        return jsonify({}), 200

    elif request.method == 'GET':
        # pretty print?
        pp = request.args.get('pp', None)
        if pp is not None:
            pp = pp.lower()
            if pp == 'true':
                pp = True
            elif pp == 'false':
                pp = False
            else:
                abort(400, description='Invalid value for pp argument')

        if pp is True:
            return jsonify(variables), 200
        else:
            return jsonify({k: variables[k] for k in sorted(variables)}), 200
    else:
        abort(405)  # method not allowed

@app.route('/variables/<var_name>', methods=['GET', 'DELETE'])
def handle_variable(var_name):
    if request.method == 'GET':
        if var_name not in variables:
            abort(404, description='Variable not found')

        return jsonify(variables[var_name]), 200

    elif request.method == 'DELETE':
        if var_name not in variables:
            abort(404, description='Variable not found')

        del variables[var_name]
        return jsonify({}), 200
    else:
        abort(405)  # method not allowed


if __name__ == '__main__':
    app.run()

