@admin_challenges.route('/challenges', methods=['GET'])
@login_required
@admins_only
def list_challenges():
    if is_admin():
        challenges = Challenges.query.order_by(Challenges.id.asc()).all()
    else:
        challenges = Challenges.query.filter_by(state='view').order_by(Challenges.id.asc()).all()
    return render_template('challenges.html', challenges=challenges)


@admin_challenges.route('/challenges', methods=['POST'])
@login_required
@admins_only
def create_challenge():
    form = CreateChallengeForm(request.form)
    if form.validate():
        challenge = Challenges(
            name=form.title.data,
            description=form.description.data,
            category=form.category.data,
            value=form.value.data,
            state=form.state.data,
            type=form.type.data
        )
        db.session.add(challenge)
        db.session.commit()

        if form.type.data == 'standard':
            chal_class = get_chal_class('standard')
            chal = chal_class(
                challenge_id=challenge.id,
                requirements=form.requirements.data
            )
        elif form.type.data == 'file':
            chal_class = get_chal_class('file')
            chal = chal_class(
                challenge_id=challenge.id,
                requirements=form.requirements.data
            )
        else:
            chal = None

        if chal:
            db.session.add(chal)
            db.session.commit()

        flash('Challenge Created', 'success')
        return redirect(url_for('admin_challenges.list_challenges'))
    return render_template('404.html'), 404


