@admin_challenges.route('/challenges/solve/<int:challenge_id>', methods=['POST'])
@login_required
def solve_challenge(challenge_id):
    if current_user.is_admin:
        return redirect(url_for('challenges.route', challenge_id=challenge_id))

    challenge = Challenges.query.filter_by(id=challenge_id).first_or_404()
    if challenge.state != 'visible':
        return redirect(url_for('challenges.route', challenge_id=challenge_id))

    submission = Submissions(
        challenge_id=challenge_id,
        user_id=current_user.id,
        ip=get_ip()
    )
    db.session.add(submission)
    db.session.commit()

    flag_class = get_flag_class()
    flag = flag_class.get_by_content(request.form['flag'], challenge_id)

    if flag:
        if not challenge.can_be_viewed_by(current_user):
            return redirect(url_for('challenges.route', challenge_id=challenge_id))

        if challenge.requirements:
            if not current_user.can_view(challenge):
                flash('You do not have the required permissions to solve this challenge', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))

        if challenge.type == 'standard':
            if flag.chal != challenge.id:
                flash('Incorrect flag', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))
        elif challenge.type == 'file':
            if not flag.chal in challenge.id:
                flash('Incorrect flag', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))
        else:
            flash('Incorrect flag', 'error')
            return redirect(url_for('challenges.route', challenge_id=challenge_id))

        if challenge.state != 'visible':
            flash('Challenge is not visible', 'error')
            return redirect(url_for('challenges.route', challenge_id=challenge_id))

        if challenge.category != "pwn":
            if challenge.value <= current_user.score:
                flash('Incorrect flag', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))
            else:
                current_user.score = current_user.score - challenge.value
                db.session.add(current_user)
                db.session.commit()
        else:
            team = get_current_team()
            if not team:
                flash('You must be on a team to solve pwn challenges', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))
            if challenge.value <= team.score:
                flash('Incorrect flag', 'error')
                return redirect(url_for('challenges.route', challenge_id=challenge_id))
            else:
                team.score = team.score - challenge.value
                db.session.add(team)
                db.session.commit()

        challenge.solves = challenge.solves + 1
        db.session.add(challenge)
        db.session.commit()

        submission.correct = True
        db.session.add(submission)
        db.session.commit()

        if challenge.type != 'standard':
            flag.chal = flag.chal + 1
            db.session.add(flag)
            db.session.commit()

        if challenge.type == 'pwn':
            team = get_current_team()
            if team:
                award = Awards(
                    team_id=team.id,
                    name="Solved " + challenge.name,
                    description="Solved a pwn challenge",
                    value=challenge.value,
                    category=challenge.category
                )
                db.session.add(award)
                db.session.commit()

        flash('Correct', 'success')
    else:
        flash('Incorrect', 'error')
    return redirect(url_for('challenges.route', challenge_id=challenge_id))

