func (c *Client) Get(lat, lon float64, t time.Time) (*Forecast, error) {
	forecast := new(Forecast)
	forecast.Coord = NewCoord(lat, lon)
	forecast.GeneratedAt = t

	url := c.baseURL + "/forecast"
	params := url.Values{}
	params.Add("lat", strconv.FormatFloat(lat, 'f', -1, 64))
	params.Add("lon", strconv.FormatFloat(lon, 'f', -1, 64))
	params.Add("appid", c.apiKey)
	params.Add("units", c.units)
	params.Add("lang", c.lang)

	if c.cnt != 0 {
		params.Add("cnt", strconv.Itoa(c.cnt))
	}

	if c.exclude != "" {
		params.Add("exclude", c.exclude)
	}

	url += "?" + params.Encode()

	resp, err := c.get(url)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, c.errorHandler(resp)
	}

	if err := json.NewDecoder(resp.Body).Decode(forecast); err != nil {
		return nil, err
	}

	forecast.City, err = c.getCity(forecast.City.ID)
	if err != nil {
		return nil, err
	}

	return forecast, nil
