// NewClient creates a new openweathermap client
func NewClient(apiKey string) *Client {
	return &Client{
		baseURL:    "https://api.openweathermap.org/data/2.5",
		apiKey:     apiKey,
		units:      "metric",
		lang:       "en",
		httpClient: &http.Client{},
	}
}

// SetUnits sets the units for the client, can be "standard", "metric" or "imperial"
func (c *Client) SetUnits(units string) *Client {
	c.units = units
