  var timeout = options.timeout;
  var shell = options.shell;

  if (inputFile) {
    input = fs.readFileSync(inputFile, 'utf8');
  }

  if (outputFile) {
    output = fs.openSync(outputFile, 'w');
  }

  try {
    var result = child_process.execSync(
      command,
      {
        input: input,
        output: output,
        timeout: timeout,
        shell: shell
      }
    );

    if (outputFile) {
