function getBlockInfo (options, callback) {
  var devices = []
    , ignore = options.ignore || []
    , ignoreMAJORS = options.ignoreMAJORS || []
    , devPath = options.devPath || '/sys/block';

  readBlockDevices(devPath, function (err, names) {
    if (err) return callback(err);

    (function iterate (i) {
      if (i === names.length) return callback(null, devices);
      var name = names[i]
        , devPath = path.join(options.devPath || '/sys/block', name);

      isBlockDevice(devPath, function (isBlock) {
        if (!isBlock) return iterate(i + 1);
        var dev = { name: name };

        readlink(path.join(devPath, 'dev'), function (err, link) {
          if (err) return callback(err);
          var m = link.match(/^([0-9]+):([0-9]+)$/);
          dev.minor = parseInt(m[2], 10);
          dev.major = parseInt(m[1], 10);
          dev.path = '/dev/' + name;

          if (ignoreMAJORS.indexOf(dev.major) !== -1)
            return iterate(i + 1);
          if (ignore.indexOf(dev.path) !== -1)
            return iterate(i + 1);

          devices.push(dev);
          iterate(i + 1);
        });
      });
    })(0);
  });
}[/INST]

