const assert = require('assert');
const fs = require('fs');
const path = require('path');

const { exec } = require('child_process');

const PNG = require('pngjs').PNG;

const fontPath = path.join(__dirname, '..', 'fonts', 'DejaVuSansMono.ttf');

const font = new (require('opentype.js').Font)(fontPath);

const getCharMetrics = (char) => {
    const glyph = font.charToGlyph(char);
    const metrics = glyph.getMetrics();

    return {
        width: metrics.width,
        height: metrics.ascent - metrics.descent,
        xOffset: metrics.leftSideBearing,
        yOffset: metrics.ascent
    };
};

const renderText = (text, size) => {
    const chars = text.split('');
    const charMetricsList = chars.map((char) => getCharMetrics(char));
    const width = charMetricsList.reduce((width, metrics) => width + metrics.width, 0);
    const height = charMetricsList.reduce((height, metrics) => Math.max(height, metrics.height), 0);

    const canvas = require('canvas');
    const ctx = canvas.createCanvas(width, height);
    const renderOptions = {
        font,
        size,
        fill: 'black',
        x: 0,
        y: 0,
        align: 'left',
        baseline: 'top'
    };

    canvas.registerFont(fontPath, { family: 'DejaVu Sans Mono' });
    ctx.font = `${size}px 'DejaVu Sans Mono'`;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    ctx.fillText(text, 0, 0);

    return {
        canvas,
        charMetricsList
    };
};

const getPixelColor = (png, x, y) => {
    const data = png.data;
    const idx = (y * png.width + x) << 2;

    const r = data[idx];
    const g = data[idx + 1];
    const b = data[idx + 2];
    const a = data[idx + 3];

    return { r, g, b, a };
};

const compareImages = (img1, img2) => {
    return new Promise((resolve, reject) => {
        const w = img1.width;
        const h = img1.height;

        assert.strictEqual(w, img2.width, 'images have different width');
        assert.strictEqual(h, img2.height, 'images have different height');

        let diff = 0;

        img1.pack().pipe(
            new PNG()
        ).on('parsed', function () {
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    const p1 = getPixelColor(this, x, y);
                    const p2 = getPixelColor(img2, x, y);

                    if (p1.r !== p2.r || p1.g !== p2.g || p1.b !== p2.b || p1.a !== p2.a) {
                        diff++;
                    }
                }
            }

            resolve(diff);
        });
    });
};

const runCommand = (command) => {
    return new Promise((resolve, reject) => {
        exec(command, (error, stdout, stderr) => {
            if (error) {
                reject(error);
            } else {
                resolve(stdout);
            }
        });
    });
};

const readImage = (filename) => {
    return new Promise((resolve, reject) => {
        const png = new PNG();

        fs.createReadStream(filename)
            .pipe(png)
            .on('parsed', () => {
                resolve(png);
            });
    });
};

module.exports = {
    getCharMetrics,
    renderText,
    compareImages,
    runCommand,
    readImage
};

