function tileImage(image, options) {
  options = Object.assign({
    width:  256,
    height: 256,
    margin: 0,
    format: "image/png",
    quality: 1.0
  }, options);

  const { width, height, margin, format, quality } = options;

  let canvas = document.createElement("canvas");
  let context = canvas.getContext("2d");

  let tileWidth  = width  + margin;
  let tileHeight = height + margin;

  let tilesPerRow  = Math.floor(canvas.width  / tileWidth);
  let tilesPerCol  = Math.floor(canvas.height / tileHeight);

  let numTiles = 0;

  function saveTile(row, col, callback) {
    let tile = {
      row: row,
      col: col,
      image: null
    };

    numTiles++;

    let tileCanvas = document.createElement("canvas");
    tileCanvas.width  = width;
    tileCanvas.height = height;
    let tileContext = tileCanvas.getContext("2d");

    let sx = col * tileWidth;
    let sy = row * tileHeight;

    tileContext.drawImage(image, -sx, -sy);

    tile.image = tileCanvas.toDataURL(format, quality);

    callback(null, tile);
  }

  function done(err) {
    if (err) {
      callback(err);
      return;
    }

    let tiles = [];
    for (let row = 0; row < tilesPerCol; row++) {
      for (let col = 0; col < tilesPerRow; col++) {
        tiles.push(tiles[row * tilesPerRow + col]);
      }
    }

    callback(null, tiles);
  }

  function layout(callback) {
    let row, col;

    for (row = 0; row < tilesPerCol; row++) {
      for (col = 0; col < tilesPerRow; col++) {
        saveTile(row, col, callback);
      }
    }

    callback(null, numTiles);
  }

  layout(done);

  return canvas;
}

