    <S.Matches>
      {matches.map((match, matchIdx) => (
        <S.Match key={matchIdx}>
          <S.MatchDetails>
            <Link to={`/repo/${repository.name}/file/${match.path}`}>
              <S.FilePath>{match.path}</S.FilePath>
            </Link>
            <span>
              {match.lineNumber} {pluralize('line', match.lineNumber)}
            </span>
            <RelativeTime timestamp={match.addedAt} />
          </S.MatchDetails>

          <S.MatchPreview>
            {match.highlights.map((highlight, highlightIdx) => (
              <S.Line key={highlightIdx}>
                {highlight.type === 'match' && (
                  <HighlightMatch match={highlight.match} pre={highlight.pre} />
                )}
                {highlight.type === 'surrounding' && (
                  <span>{highlight.pre}</span>
                )}
              </S.Line>
            ))}
          </S.MatchPreview>
        </S.Match>
      ))}
    </S.Matches>
  </S.Container>
);

export default RepositoryMatches;

