import React from 'react';
import { Link } from 'react-router-dom';
import { FormattedMessage, useIntl } from 'react-intl';
import { Row, Col } from 'react-bootstrap';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faUser, faList, faLink } from '@fortawesome/free-solid-svg-icons';
import { getLocalTime } from '../../../utils/misc';
import { USER_PROFILE, USER_CONTRIBUTIONS, USER_LINKS } from '../../../utils/paths';
import { PAGE_DETAILS } from '../../../utils/paths';
import EntityList from '../../entity/EntityList';
import UserAvatar from '../UserAvatar';
import UserEdit from '../UserEdit';
import PageTitle from '../../layout/PageTitle';
import Breadcrumb from '../../layout/Breadcrumb';
import Loading from '../../layout/Loading';

const UserProfile = ({ user, page, entity, lists, loading }) => {
  const intl = useIntl();

  if (loading) {
    return <Loading />;
  }

  return (
    <Row>
      <Col>
        <PageTitle title={user.name} icon={faUser} />
        <Breadcrumb
          crumbs={[
            { name: <Link to={PAGE_DETAILS}>Home</Link>, active: false },
            { name: <Link to={USER_PROFILE}>Users</Link>, active: false },
            { name: user.name, active: true },
          ]}
        />
        <Row className="mb-3">
          <Col md={2} className="d-flex align-items-center">
            <UserAvatar user={user} size={96} />
          </Col>
          <Col md={10}>
            <h2 className="mb-0 d-inline-block">
              {user.name}
              {user.is_bot && (
                <span className="badge bg-secondary ms-2">
                  <FormattedMessage id="user.isBot" defaultMessage="Bot" />
                </span>
              )}
            </h2>
            <p className="mb-0 opacity-75">
              <small>
                <FormattedMessage
                  id="user.accountCreatedOn"
                  defaultMessage="Account created on"
                />{' '}
                {getLocalTime(user.created)}
              </small>
            </p>
            {user.languages.length > 0 && (
              <p className="mb-0 opacity-75">
                <small>
                  <FormattedMessage
                    id="user.languages"
                    defaultMessage="Languages:"
                  />{' '}
                  {user.languages.join(', ')}
                </small>
              </p>
            )}
            {user.location && (
              <p className="mb-0 opacity-75">
                <small>
                  <FormattedMessage
                    id="user.location"
                    defaultMessage="Location:"
                  />{' '}
                  {user.location}
                </small>
              </p>
            )}
            {user.bio && (
              <p className="mb-0 opacity-75">
                <small>
                  <FormattedMessage id="user.bio" defaultMessage="Bio:" />{' '}
                  {user.bio}
                </small>
              </p>
            )}
            <UserEdit user={user} page={page} entity={entity} />
          </Col>
        </Row>
        <Row>
          <Col>
            <h3>
              <FontAwesomeIcon icon={faList} className="me-2" />
              <FormattedMessage id="user.contributions" defaultMessage="Contributions" />
            </h3>
            <EntityList
              entities={lists}
              title={intl.formatMessage({
                id: 'user.contributions',
                defaultMessage: 'Contributions',
              })}
              path={USER_CONTRIBUTIONS}
              params={{ username: user.name }}
              page={page}
              entity={entity}
            />
          </Col>
        </Row>
        {user.links.length > 0 && (
          <Row>
            <Col>
              <h3>
                <FontAwesomeIcon icon={faLink} className="me-2" />
                <FormattedMessage id="user.links" defaultMessage="Links" />
              </h3>
              <EntityList
                entities={user.links}
                title={intl.formatMessage({
                  id: 'user.links',
                  defaultMessage: 'Links',
                })}
                path={USER_LINKS}
                params={{ username: user.name }}
                page={page}
                entity={entity}
              />
            </Col>
          </Row>
        )}
      </Col>
    </Row>
  );
};

export default UserProfile;

