    const file = req.file;
    const emailRegex = /^(([^<>()[\]\\.,;:\s@\"]+(\.[^<>()[\]\\.,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;

    const results = fs.readFileSync(file.path, 'utf8').split('\n').map(e => e.trim()).filter(e => e.length > 0 && emailRegex.test(e));

    client.query('BEGIN', (err, result) => {
        if (err) {
            console.log(err.stack)
            res.status(500).send("Database error");
        } else {
            const insertQuery = 'INSERT INTO consented(email) VALUES($1) ON CONFLICT DO NOTHING';
            const params = [];
            results.forEach((result, i) => {
                params.push(result);
                if (params.length === 1000 || i === results.length - 1) {
                    client.query(insertQuery, params, (err, result) => {
                        if (err) {
                            console.log(err.stack)
                            res.status(500).send("Database error");
