function updateNote(operation: Operation, db: IDBDatabase) {
  const { noteId, start, length, text } = operation;
  const noteObjectStore = db
    .transaction(['notes'], 'readwrite')
    .objectStore('notes');

  const noteUpdate = noteObjectStore.get(noteId);

  noteUpdate.onerror = (event) => {
    console.error('Note update has failed.', event);
  };

  noteUpdate.onsuccess = (event) => {
    const note = (event.target as IDBRequest).result as Note;

    if (!note) {
      console.error(`Note ${noteId} doesn't eist.`);
      return;
    }

    const newNote = { ...note };

    if (operation.type === 'delete') {
      newNote.text = note.text.slice(0, start) + note.text.slice(start + length);
    } else if (operation.type === 'insert') {
      newNote.text =
        note.text.slice(0, start) + text + note.text.slice(start);
    }

    const request = noteObjectStore.put(newNote);

    request.onerror = (event) => {
      console.error('Note update has failed.', event);
    };

    request.onsuccess = () => {
      console.info('Note updated successfully.');
    };
  };
}

