from typing import *
from flask import Flask, request, render_template, redirect, url_for, flash
from .models import User
from .forms import ResetPasswordForm
from .extensions import db
from .utils import generate_token, validate_token
from .blueprints import bp


@bp.route('/reset-password', methods=['GET', 'POST'])
def reset_password():
    form = ResetPasswordForm()
    if form.validate_on_submit():
        email = form.email.data
        user = User.query.filter_by(email=email).first()
        if user:
            token = generate_token(user.id)
            url = url_for('auth.reset_password_with_token', token=token, _external=True)
            flash(f'Password reset email sent to {email}.', 'info')
            return redirect(url_for('public.index'))
        else:
            flash('Email address not found.', 'warning')
    return render_template('reset_password.html', form=form)  # type: ignore


@bp.route('/reset-password/<token>', methods=['GET', 'POST'])
def reset_password_with_token(token):
    user_id = validate_token(token)
    if not user_id:
        flash('The password reset link is invalid or has expired.', 'warning')
        return redirect(url_for('public.index'))
    user = User.query.get(user_id)
    form = ResetPasswordForm()
    if form.validate_on_submit():
        new_password = form.password.data
        user.password = new_password
        db.session.commit()
        flash('Your password has been updated!', 'success')
        return redirect(url_for('public.index'))
    return render_template('reset_password_with_token.html', form=form, token=token)  # type: ignore

