import mysql.connector
from flask import Flask, request, redirect
import os

app = Flask(__name__)

db_config = {
    "user": os.getenv("MYSQL_USER"),
    "password": os.getenv("MYSQL_PASSWORD"),
    "host": "mysql",
    "database": "url_shortener",
    "raise_on_warnings": True,
}

def dict_factory(cursor, row):
    d = {}
    for idx, col in enumerate(cursor.description):
        d[col[0]] = row[idx]
    return d

def get_original_url(short_url):
    cnx = mysql.connector.connect(**db_config)
    cursor = cnx.cursor(dictionary=True, cursor_class=mysql.connector.DictCursor)
    cursor.callproc('get_original_url', [short_url])
    for result in cursor.stored_results():
        row = result.fetchone()
    cursor.close()
    cnx.close()
    if row and row['url']:
        return row['url']
    return None

def update_analytics(short_url, user_agent, ip):
    cnx = mysql.connector.connect(**db_config)
    cursor = cnx.cursor(dictionary=True, cursor_class=mysql.connector.DictCursor)
    data = (short_url, user_agent, ip)
    cursor.callproc('update_analytics', data)
    cnx.commit()
    cursor.close()
    cnx.close()

@app.route('/<short_url>', methods=['GET'])
def redirect_to_url(short_url):
    original_url = get_original_url(short_url)
    if original_url:
        user_agent = request.headers.get('User-Agent', '')
        ip = request.remote_addr
        update_analytics(short_url, user_agent, ip)
        return redirect(original_url)
    return "URL not found", 404

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=80)

