def self.search(user, query, page = 1, per_page = 10, sort = nil, order = nil, taxon_concept_id: nil, parent_taxon_concept_id: nil, rank: nil, nomenclature_date: nil, include_synonyms: nil, include_child_taxon_concepts: nil, **filters)
  return [] if query.blank? && filters.values.all?(&:blank?)

  query = "%#{query.strip}%"

  search = self.__elasticsearch__.client.search(
    index: self.__elasticsearch__.index_name,
    body:  build_search_query(query, page, per_page, sort, order, taxon_concept_id, parent_taxon_concept_id, rank, nomenclature_date, include_synonyms, include_child_taxon_concepts, **filters)
  )

  hits = search['hits']['hits'].map { |hit| TaxonConcept.find(hit['_id']) }

  WillPaginate::Collection.create(page, per_page, search['hits']['total']['value']) do |pager|
    pager.replace(hits)
  end
rescue Elasticsearch::Transport::Transport::Errors::NotFound
  []
end

def self.build_search_query(query, page, per_page, sort, order, taxon_concept_id, parent_taxon_concept_id, rank, nomenclature_date, include_synonyms, include_child_taxon_concepts, **filters)
  must_clauses = []
  filter_clauses = []

  must_clauses << { multi_match: { query: query, fields: %w(complete_name name) } }

  filters.each do |key, value|
    if value.present?
      if value.is_a?(Array)
        filter_clauses << { terms: { key => value } }
      else
        filter_clauses << { term: { key => value } }
      end
    end
  end

  must_clauses << { bool: { must: filter_clauses } } if filter_clauses.any?

  must_clauses << { term: { is_valid: true } }

  must_clauses << { term: { is_sensitive: false } } if user.try(:admin?) == false

  must_not_clauses = []

  must_not_clauses << { term: { is_valid: false } }

  must_not_clauses << { term: { is_sensitive: true } }

  {
    from:          (page - 1) * per_page,
    size:          per_page,
    sort:          [{ complete_name: { order: sort_order(sort, order) } }],
    query:         { bool: { must: must_clauses, must_not: must_not_clauses } },
    track_scores:  true,
    _source:       include_child_taxon_concepts ? %w(complete_name name rank nomenclature_date child_taxon_concept_ids) : %w(complete_name name rank nomenclature_date)
  }
end

def self.sort_order(sort, order)
  order ||= 'asc'
  case sort
  when 'name'
    { name: { order: order } }
  when 'complete_name'
    { complete_name: { order: order } }
  when 'rank'
    { rank: { order: order } }
  when 'nomenclature_date'
    { nomenclature_date: { order: order } }
