function parseParams(params) {
  const decodedParams = decodeURIComponent(params);
  const paramArray = decodedParams.split('&');

  const result = paramArray.reduce((prev, curr) => {
    const [key, value] = curr.split('=');

    if (key.includes('.')) {
      const keys = key.split('.');
      let objRef = prev;

      keys.forEach((k, i) => {
        if (i === keys.length - 1) {
          objRef[k] = value;
        } else {
          if (!objRef[k]) objRef[k] = {};
          objRef = objRef[k];
        }
      });
    } else {
      prev[key] = value;
    }

    return prev;
  }, {});

  return result;
}

