		var b = iframes[i].getAttribute("data-resize");
		if (b == "true" || b == "both" || b == undefined) {
			iframes[i].oldHeight = iframes[i].height;
		}
		b = iframes[i].getAttribute("data-embed");
		if (b == "true") {
			iframes[i].src = iframes[i].src;
		}
	}
}

function receiveMessage(event) {
	var origin = event.origin || event.originalEvent.origin;
	if (origin != "http://fiddle.jshell.net" && origin != "https://fiddle.jshell.net") {
		return;
	}

	var iframes = document.getElementsByTagName("iframe");
	for (var i = 0; i < iframes.length; i++) {
		if (event.source == iframes[i].contentWindow) {
			var height = event.data;
			if (isNaN(height) == false) {
				iframes[i].height = height + "px";
			} else if (event.data == "resize") {
				if (iframes[i].oldHeight) {
