            JarEntry entry = new JarEntry(LAYER_XML_PATH);
            jarOut.putNextEntry(entry);
            byte[] buffer = contents.getBytes();
            jarOut.write(buffer, 0, buffer.length);
            jarOut.closeEntry();
        } catch (Exception ignored) {
