private static void checkOutputDirectory(Path outputDirectory, Path file, boolean shouldExist)
            throws IOException {
    if (!outputDirectory.isAbsolute()) {
        throw new RelativePathException(outputDirectory);
    }
    Path absoluteFile = file.isAbsolute() ? file : outputDirectory.resolve(file);
    if (shouldExist) {
        if (!Files.exists(absoluteFile)) {
            throw new FileNotFoundException("Cannot find: " + absoluteFile);
        }
    } else {
        if (Files.exists(absoluteFile)) {
            throw new FileAlreadyExistsException("Cannot overwrite: " + absoluteFile);
        }
    }
    Path parent = absoluteFile.getParent();
    if (parent != null && !Files.isDirectory(parent)) {
        throw new NotDirectoryException(parent.toString());
    } else if (!outputDirectory.normalize().equals(parent.normalize())) {
        throw new SecurityException("Cannot output to a different directory');
    }
}

