const http = require('http');
const url = require('url');
const path = require('path');
const fs = require('fs');
const zlib = require('zlib');

const port = process.env.PORT || 3000;

const liveReloadPort = 35729;
const liveReloadScript = `http://localhost:${liveReloadPort}/livereload.js`;

const send404 = (res) => {
	res.writeHead(404);
	res.end('404: File Not Found');
};

const getFile = (filePath, res) => {
	const type = path.extname(filePath).slice(1);
	res.setHeader('Content-Type', `text/${type}`);
	fs.readFile(filePath, (err, data) => {
		if (err) {
			send404(res);
		} else {
			res.end(data);
		}
	});
};

const server = http.createServer((req, res) => {
	const parsedUrl = url.parse(req.url, true);
	const parsedPath = url.parse(req.url).pathname;
	const cleanedPath = path.normalize(parsedPath).slice(1);
	const filePath = path.join(__dirname, 'public', cleanedPath);

	if (fs.existsSync(filePath) && fs.lstatSync(filePath).isFile()) {
		if (path.extname(filePath) === '.html') {
			getFile(filePath, res);
			return;
		}

		fs.readFile(filePath, (err, data) => {
			if (err) {
				send404(res);
				return;
			}

			const etag = '"' + zlib.crc32(data).toString(16) + '"';
			const ifNoneMatch = req.headers['if-none-match'];

			res.setHeader('ETag', etag);

			if (ifNoneMatch && ifNoneMatch === etag) {
				res.writeHead(304);
				res.end();
				return;
			}

			if (path.extname(filePath) === '.css') {
				res.setHeader('Content-Type', 'text/css');
			} else if (path.extname(filePath) === '.js') {
				res.setHeader('Content-Type', 'application/javascript');

				if (process.env.NODE_ENV !== 'production') {
					res.setHeader('Cache-Control', 'no-cache');
				} else {
					res.setHeader('Cache-Control', 'max-age=31536000');
				}
			}

			res.setHeader('Vary', 'Accept-Encoding');

			if (req.headers['accept-encoding'].includes('gzip')) {
				res.setHeader('Content-Encoding', 'gzip');
				res.end(zlib.gzipSync(data));
			} else {
				res.end(data);
			}
		});
	} else if (fs.existsSync(path.join(__dirname, 'routes', cleanedPath + '.js'))) {
		const route = require('./routes/' + cleanedPath);

		route(req, res, () => {
			send404(res);
		});
	} else {
		send404(res);
	}
});

