def safe_join(directory, *path):
    """
    Safely joins one or more path components to the directory path,
    raising an error if directory traversal is attempted.
    """
    parts = directory.split(os.path.sep)
    for p in path:
        if p == '..':
            if parts:
                parts.pop()
        elif p and p != '.':
            parts.append(p)
    return os.path.sep.join(parts)

