def send_file_etag(path, type):
    stat_ = stat_file(path)
    if not stat_:
        abort(404)
    mtime = stat_.st_mtime
    size = stat_.st_size
    etag = f'"{mtime}_{size}"'
    headers = {'Last-Modified': http_date(mtime)}
    if request.method == 'GET':
        headers['Accept-Ranges'] = 'bytes'
    if request.headers.get('If-None-Match') == etag:
        return '', 304, headers
    response = send_file(path, conditional=True, etag=etag, add_etags=False,
                         last_modified=datetime.utcfromtimestamp(mtime),
                         mimetype=app.config['MIMETYPES'].get(type, 'application/octet-stream'))
    response.cache_control.max_age = 86400
    return response


