ud_cache_conn(struct ud_conn *conn, struct sk_buff *skb)
{
	struct ud_sock *us = ud_sk(conn->sk);
	struct sock *sk = conn->sk;
	u16 family = sk->sk_family;
	__be16 *ports = ud_ports(skb);
	struct ud_addr *addr;
	struct rb_node **p;
	struct rb_node *parent = NULL;
	unsigned long hash;
	struct ud_cache *c;
	int overwrite = 0;

	if (sk->sk_state != TCP_ESTABLISHED)
		return;

	hash = udp_hashfn(family, skb->daddr, skb->saddr, ports[0], ports[1],
			  us->lport);
	p = &us->ht_root.rb_node;

	while (*p) {
		parent = *p;
		c = rb_entry(parent, struct ud_cache, node);

		if (hash < c->hash)
			p = &(*p)->rb_left;
		else if (hash > c->hash)
			p = &(*p)->rb_right;
		else {
			if (before(ports[0], c->port))
				p = &(*p)->rb_left;
			else if (before(c->port, ports[0]))
				p = &(*p)->rb_right;
			else {
				if (family == AF_INET6 &&
				    ipv6_addr_cmp(&c->daddr, &skb->daddr))
					p = &(*p)->rb_left;
				else if (family == AF_INET6 &&
					 ipv6_addr_cmp(&skb->daddr,
							&c->daddr))
					p = &(*p)->rb_right;
				else
					/* Found it! */
					goto found;
			}
		}
	}

	/* Not found. Create a new cache entry */
	c = ud_cache_alloc();
	if (!c)
		goto out;

	c->hash = hash;
	c->port = ports[0];
	udp_copy_addr(&c->daddr, family, &skb->daddr);
	rb_link_node(&c->node, parent, p);
	rb_insert_color(&c->node, &us->ht_root);

found:
	/* Overwrite old cache entry */
	c->saddr = skb->saddr;
	c->family = family;
	c->skb = skb;
	udp_cache_hold(c);
	if (c->sk) {
		sock_hold(c->sk);
		sock_wake_up(c->sk);
	}
	overwrite = 1;

out:
	if (overwrite)
		atomic_long_inc(&conn->counter->cached);
	else
		atomic_long_inc(&conn->counter->skipped);
}

